import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';

interface VaultItem {
    fileName: string;
    ipfsHash: string;
    fileHash: string;
    uploadedAt: string;
    status: string;
    sharedWith: string[];
}

const Vault: React.FC = () => {
    const { token } = useAuth();
    const [file, setFile] = useState<File | null>(null);
    const [vaultItems, setVaultItems] = useState<VaultItem[]>([]);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [sharingWith, setSharingWith] = useState<{ [key: string]: string }>({});

    useEffect(() => {
        fetchVault();
    }, []);

    const fetchVault = async () => {
        try {
            const res = await fetch('http://localhost:5000/api/vault', {
                headers: { 'x-auth-token': token || '' }
            });
            const data = await res.json();
            if (res.ok) setVaultItems(data);
        } catch (err) {
            console.error('Fetch error:', err);
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) setFile(e.target.files[0]);
    };

    const hashFile = async (file: File): Promise<string> => {
        const buffer = await file.arrayBuffer();
        const hashBuffer = await crypto.subtle.digest('SHA-256', buffer);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    };

    const handleUpload = async () => {
        if (!file || !token) return;
        setLoading(true);
        setMessage('');

        try {
            // 1. Generate Local Hash
            const fileHash = await hashFile(file);

            // 2. Upload to IPFS (Placeholder for actual Pinata call)
            // In a real scenario, you'd call Pinata API here. 
            // For now we simulate the IPFS hash generation.
            const ipfsHash = `Qm${Math.random().toString(36).substring(2, 15)}${Math.random().toString(36).substring(2, 15)}`;

            // 3. Save to Backend Vault
            const res = await fetch('http://localhost:5000/api/vault/add', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'x-auth-token': token 
                },
                body: JSON.stringify({
                    fileName: file.name,
                    ipfsHash: ipfsHash,
                    fileHash: fileHash
                })
            });

            if (res.ok) {
                setMessage('Document successfully secured in vault and pinned to IPFS.');
                setFile(null);
                fetchVault();
            } else {
                const data = await res.json();
                throw new Error(data.message || 'Upload failed');
            }
        } catch (err: any) {
            setMessage(`Upload Error: ${err.message}`);
        } finally {
            setLoading(false);
        }
    };

    const handleShare = async (fileHash: string) => {
        const entity = sharingWith[fileHash];
        if (!entity || !token) return;

        try {
            const res = await fetch('http://localhost:5000/api/vault/share', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'x-auth-token': token 
                },
                body: JSON.stringify({ fileHash, entityName: entity })
            });

            if (res.ok) {
                setMessage(`Certificate successfully shared with ${entity}`);
                setSharingWith({ ...sharingWith, [fileHash]: '' });
                fetchVault();
            }
        } catch (err) {
            console.error('Share error:', err);
        }
    };

    return (
        <div className="fade-in" style={{ maxWidth: '1000px', margin: '0 auto' }}>
            <div style={{ marginBottom: '4rem' }}>
                <h1 style={{ fontSize: '3rem' }}>Document Vault</h1>
                <p style={{ color: 'var(--text-secondary)', fontSize: '1.2rem' }}>
                    Securely store cryptographic proofs of your documents on IPFS and manage access.
                </p>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '350px 1fr', gap: '3rem' }}>
                {/* Upload Section */}
                <div>
                    <div className="glass" style={{ padding: '2.5rem' }}>
                        <h3 style={{ marginBottom: '1.5rem' }}>Secure New Asset</h3>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                            <div className="file-input-wrapper" style={{ 
                                border: '2px dashed var(--card-border)', 
                                padding: '2.5rem 1.5rem', 
                                textAlign: 'center',
                                borderRadius: '12px',
                                cursor: 'pointer'
                            }}>
                                <input type="file" onChange={handleFileChange} style={{ opacity: 0, position: 'absolute', width: '100%', height: '100%', left: 0, top: 0, cursor: 'pointer' }} />
                                <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>↥</div>
                                <p style={{ fontSize: '0.85rem' }}>{file ? file.name : 'Tap to upload or drag identity document'}</p>
                            </div>

                            <button 
                                onClick={handleUpload} 
                                disabled={!file || loading} 
                                className="btn btn-primary"
                                style={{ width: '100%' }}
                            >
                                {loading ? 'Hashing & Pinning...' : 'Vault Document'}
                            </button>

                            {message && (
                                <p style={{ 
                                    fontSize: '0.8rem', 
                                    color: message.includes('Error') ? 'var(--error)' : 'var(--success)',
                                    marginTop: '1rem',
                                    textAlign: 'center'
                                }}>
                                    {message}
                                </p>
                            )}
                        </div>
                    </div>

                    <div className="glass" style={{ padding: '2rem', marginTop: '2rem' }}>
                        <h4>Vault Policy</h4>
                        <ul style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', paddingLeft: '1.2rem', marginTop: '1rem' }}>
                            <li style={{ marginBottom: '0.8rem' }}>Files are hashed locally before transmission.</li>
                            <li style={{ marginBottom: '0.8rem' }}>Storage is handled by IPFS decentralized nodes.</li>
                            <li>Sharing is purely cryptographic; you grant viewing rights to hashes.</li>
                        </ul>
                    </div>
                </div>

                {/* Vault List */}
                <div className="glass" style={{ padding: '2.5rem', minHeight: '600px' }}>
                    <h3 style={{ marginBottom: '2rem' }}>Secured Assets</h3>
                    {vaultItems.length === 0 ? (
                        <div style={{ textAlign: 'center', marginTop: '8rem', opacity: 0.5 }}>
                            <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🗄</div>
                            <p>No documents found in your vault.</p>
                        </div>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                            {vaultItems.map((item, idx) => (
                                <div key={idx} className="glass" style={{ padding: '1.5rem', border: '1px solid rgba(255,255,255,0.05)' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                                        <div>
                                            <h4 style={{ margin: 0, fontSize: '1.1rem' }}>{item.fileName}</h4>
                                            <p style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '0.4rem', fontFamily: 'monospace' }}>
                                                CID: {item.ipfsHash}
                                            </p>
                                        </div>
                                        <div className="status-badge status-verified" style={{ padding: '0.2rem 0.8rem' }}>{item.status}</div>
                                    </div>

                                    <div className="divider" style={{ margin: '1rem 0' }}></div>

                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                        <div style={{ display: 'flex', gap: '0.5rem' }}>
                                            {item.sharedWith.length > 0 ? (
                                                item.sharedWith.map((sw, i) => (
                                                    <span key={i} style={{ fontSize: '0.65rem', background: 'rgba(255,255,255,0.1)', padding: '0.2rem 0.6rem', borderRadius: '4px' }}>
                                                        Shared: {sw}
                                                    </span>
                                                ))
                                            ) : (
                                                <span style={{ fontSize: '0.65rem', color: 'var(--text-muted)' }}>Not shared yet</span>
                                            )}
                                        </div>

                                        <div style={{ display: 'flex', gap: '0.5rem' }}>
                                            <input 
                                                type="text" 
                                                placeholder="Recipient (e.g. Bank)" 
                                                value={sharingWith[item.fileHash] || ''}
                                                onChange={(e) => setSharingWith({ ...sharingWith, [item.fileHash]: e.target.value })}
                                                style={{ fontSize: '0.75rem', padding: '0.4rem', width: '150px' }}
                                            />
                                            <button 
                                                onClick={() => handleShare(item.fileHash)}
                                                className="btn btn-outline" 
                                                style={{ padding: '0.4rem 0.8rem', fontSize: '0.75rem' }}
                                            >
                                                Share Proof
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Vault;
